// Example: EventBridge rule for detecting abnormal ACL modifications
const rule = new events.Rule(this, 'ACLAnomalyRule', {
  eventPattern: {
    source: ['aws.s3'],
    detailType: ['AWS API Call via CloudTrail'],
    detail: {
      eventName: ['PutObjectAcl', 'GetObjectAcl'],
